Distribución geográfica de especies: la co-existencia de especies en un espacio y tiempo brinda un marco regional para la ocurrencia de interacciones entre especies, incluyéndonos.
La co-existencia regional de especies forma un marco de co-evolución entre especies, o mosaico geográfico de co-evolución, en donde las especies evolucionan en función de las características biológicas de las otras especies con las que interactúan regularmente.
La visualización de la distribución de especies de la vida silvestre, mediante mapas, ayuda en la interpretación multidisciplinar de la consulta.









⚡ Carga Ultra-Rápida: esta versión corre 100% en tu navegador con OJS (JavaScript). Primera carga: varios segundos.









Tip💡 Cómo usar este apéndice interactivo






Escribe una o más especies, un nombre científico por línea (precargado con Panthera onca y Puma concolor como ejemplo).
Verifica los nombres con el botón “🔎 Verificar nombres contra GBIF” — se confirma si GBIF reconoce cada nombre exactamente, si hay una coincidencia aproximada, o si no lo encuentra.
Define cuántos registros traer por especie con el campo “Registros máx.”
Aprieta “🗺️ Sincronizar Distribución Geográfica” para consultar GBIF y ver los puntos de ocurrencia en el mapa — cada especie con su propio color.
Explorá el mapa (zoom, desplazamiento, popups con el nombre al hacer clic).
Descargá los datos crudos en un único archivo .csv.










Importante🔎 Si dudas del nombre científico





Para que la búsqueda funcione bien, necesitas el nombre tal como lo reconoce el backbone taxonómico de GBIF. Si tienes dudas, verificalo antes en:

GBIF Species Search — la fuente misma que consulta esta app.
iNaturalist — identificación asistida por comunidad y por IA; puerta de entrada sugerida si solo tienes una foto o un nombre común.
Tropicos.org (Missouri Botanical Garden) — referencia nomenclatural para plantas.
Catalogue of Life — checklist taxonómico global de consenso.
Open Tree of Life — árbol filogenético navegable.






Código
viewof especies_input = Inputs.textarea({
  label: "Especies (una por línea):",
  value: "Panthera onca\nPuma concolor",
  rows: 5,
  resize: "vertical"
})

viewof max_registros = Inputs.range([10, 500], {
  label: "Registros máx. por especie:", 
  step: 10, 
  value: 50
})

viewof verificar_nombres_trigger = Inputs.button("🔎 Verificar nombres contra GBIF", {
  reduce: () =&gt; ({timestamp: Date.now()})
})

viewof sincronizar_trigger = Inputs.button("🗺️ Sincronizar Distribución Geográfica", {
  reduce: () =&gt; ({timestamp: Date.now()})
})

//| echo: false

// ============================================================
// SECCIÓN 2: PROCESAMIENTO DE ESPECIES Y VALIDACIÓN
// ============================================================

//| output: false

// Parseo de lista de especies desde el textarea
lista_especies = especies_input
  .split("\n")
  .map(d =&gt; d.trim())
  .filter(d =&gt; d !== "")

//| output: false

// Función para validar nombre contra GBIF
async function validarNombreGBIF(nombreEspecie) {
  const url = `https://api.gbif.org/v1/species/match?name=${encodeURIComponent(nombreEspecie)}`
  try {
    const respuesta = await fetch(url)
    const datos = await respuesta.json()
    return {
      consulta: nombreEspecie,
      encontrado: datos.matchType && datos.matchType !== "NONE",
      matchType: datos.matchType || "NONE",
      scientificName: datos.scientificName || null,
      canonicalName: datos.canonicalName || null,
      status: datos.status || null,
      error: null
    }
  } catch (error) {
    return {
      consulta: nombreEspecie,
      encontrado: false,
      matchType: "ERROR",
      error: error.message
    }
  }
}

//| output: false

// Disparador de validación reactivo
validaciones_nombres = {
  if (verificar_nombres_trigger?.timestamp) {
    return await Promise.all(
      lista_especies.map(sp =&gt; validarNombreGBIF(sp))
    )
  }
  return []
}

// Render de alertas de validación
html_validacion_nombres = html`
  &lt;div&gt;
    ${validaciones_nombres.length &gt; 0 ? validaciones_nombres.map(v =&gt; {
      if (v.matchType === "EXACT") {
        return html`&lt;div class="bio-alert bio-alert-success"&gt;
          ✅ "${v.consulta}" → reconocido como &lt;b&gt;${v.scientificName}&lt;/b&gt;
        &lt;/div&gt;`
      } else if (v.matchType === "FUZZY" || v.matchType === "PARTIAL") {
        return html`&lt;div class="bio-alert bio-alert-warning"&gt;
          ⚠️ "${v.consulta}" es aproximado. GBIF sugiere: &lt;b&gt;${v.canonicalName}&lt;/b&gt;. Revisá antes de sincronizar.
        &lt;/div&gt;`
      } else {
        return html`&lt;div class="bio-alert bio-alert-danger"&gt;
          ❌ "${v.consulta}" no se encontró en GBIF. Revisá la ortografía.
        &lt;/div&gt;`
      }
    }).join("") : html`&lt;div class="bio-alert bio-alert-info"&gt;Haz clic en "Verificar nombres" para validar.&lt;/div&gt;`}
  &lt;/div&gt;
`

//| echo: false

// ============================================================
// SECCIÓN 3: CONSULTA DE OCURRENCIAS A GBIF
// ============================================================

//| output: false

// Función para obtener puntos de ocurrencia de una especie
async function obtenerOcurrenciasGBIF(nombreEspecie, limite) {
  if (!nombreEspecie || nombreEspecie.length === 0) return []

  const url = `https://api.gbif.org/v1/occurrence/search?scientificName=${encodeURIComponent(nombreEspecie)}&hasCoordinate=true&limit=${limite}`

  try {
    const respuesta = await fetch(url)
    const datos = await respuesta.json()

    if (!datos.results || datos.results.length === 0) return []

    return datos.results
      .filter(d =&gt; d.decimalLatitude && d.decimalLongitude)
      .map(d =&gt; ({
        lat: d.decimalLatitude,
        lng: d.decimalLongitude,
        scientificName: d.scientificName || nombreEspecie,
        datasetKey: d.datasetKey || "unknown",
        especie_consultada: nombreEspecie
      }))
  } catch (error) {
    console.error(`Error consultando GBIF para ${nombreEspecie}:`, error)
    return []
  }
}

//| output: false

// Disparador de sincronización reactivo
todos_los_datos = {
  if (sincronizar_trigger?.timestamp) {
    return await Promise.all(
      lista_especies.map(sp =&gt; obtenerOcurrenciasGBIF(sp, max_registros))
    ).then(resultados =&gt; resultados.flat())
  }
  return []
}

//| output: false

// Estadísticas agregadas
estadisticas = {
  const especiesUnicas = [...new Set(todos_los_datos.map(d =&gt; d.especie_consultada))]
  return {
    especies_consultadas: especiesUnicas.length,
    registros_totales: todos_los_datos.length,
    datasets_origen: [...new Set(todos_los_datos.map(d =&gt; d.datasetKey))].length
  }
}

//| output: false

// Datos para descarga
datos_csv_export = todos_los_datos.map(d =&gt; ({
  decimalLatitude: d.lat,
  decimalLongitude: d.lng,
  scientificName: d.scientificName,
  datasetKey: d.datasetKey,
  especie_consultada: d.especie_consultada
}))

//| echo: false

// ============================================================
// SECCIÓN 4: RENDERIZADO DEL MAPA INTERACTIVO
// ============================================================

// Contenedor del mapa
container_mapa = html`&lt;div style="height: 450px; width: 100%; border-radius: 8px; border: 1px solid #ddd; margin: 16px 0;"&gt;&lt;/div&gt;`

// Lógica de renderizado del mapa (reactivo, se actualiza cuando cambian los datos)
{
  // Evitar renderizar si no hay datos
  if (todos_los_datos.length === 0) {
    container_mapa.innerHTML = `
      &lt;div style="height: 100%; display: flex; align-items: center; justify-content: center; background: #f3f4f6; color: #6b7280; font-size: 1.1em;"&gt;
        Haz clic en "🗺️ Sincronizar" para cargar datos en el mapa
      &lt;/div&gt;
    `
    invalidation.then(() =&gt; {})
    return container_mapa
  }

  // Limpiar el contenedor
  container_mapa.innerHTML = ""

  // Inicializar mapa
  const map = L.map(container_mapa).setView([0, 0], 2)

  // Capa base
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '© OpenStreetMap contributors',
    maxZoom: 19
  }).addTo(map)

  // Paleta de colores para especies (suficiente para 20+ especies)
  const colores = [
    "#3b82f6", "#ef4444", "#10b981", "#f59e0b", "#8b5cf6", 
    "#ec4899", "#06b6d4", "#84cc16", "#f97316", "#6366f1",
    "#14b8a6", "#d946ef", "#0ea5e9", "#eab308", "#64748b",
    "#fb923c", "#4ade80", "#0d9488", "#a855f7", "#e11d48"
  ]

  // Mapeo de especies a colores
  const especiesUnicas = [...new Set(todos_los_datos.map(d =&gt; d.especie_consultada))]
  const mapaColores = Object.fromEntries(
    especiesUnicas.map((esp, idx) =&gt; [esp, colores[idx % colores.length]])
  )

  // Agregar marcadores circulares con popup
  todos_los_datos.forEach(pt =&gt; {
    if (pt.lat && pt.lng && pt.lat !== 0 && pt.lng !== 0) {
      const color = mapaColores[pt.especie_consultada]
      L.circleMarker([pt.lat, pt.lng], {
        color: color,
        fillColor: color,
        radius: 5,
        weight: 1.5,
        fillOpacity: 0.7
      })
      .addTo(map)
      .bindPopup(`
        &lt;b style="font-size: 1.1em;"&gt;${pt.scientificName}&lt;/b&gt;&lt;br&gt;
        &lt;i style="font-size: 0.9em;"&gt;Consultado como: ${pt.especie_consultada}&lt;/i&gt;&lt;br&gt;
        &lt;span style="font-size: 0.8em; color: #666;"&gt;Dataset: ${pt.datasetKey}&lt;/span&gt;
      `)
    }
  })

  // Leyenda de colores como control de Leaflet, superpuesta en la esquina
  // superior derecha del mapa: no oculta puntos ni tapa el zoom
  const legendControl = L.control({position: "topright"})
  legendControl.onAdd = function() {
    const div = L.DomUtil.create("div", "bio-map-legend")
    div.innerHTML = especiesUnicas.map(esp =&gt; `
      &lt;div class="bio-map-legend-item"&gt;
        &lt;span class="bio-map-legend-dot" style="background:${mapaColores[esp]};"&gt;&lt;/span&gt;
        &lt;i&gt;${esp}&lt;/i&gt;
      &lt;/div&gt;
    `).join("")
    L.DomEvent.disableClickPropagation(div)
    return div
  }
  legendControl.addTo(map)

  // Auto-ajustar vista a los datos
  const puntosValidos = todos_los_datos.filter(pt =&gt; pt.lat && pt.lng && pt.lat !== 0 && pt.lng !== 0)
  if (puntosValidos.length &gt; 0) {
    const bounds = L.latLngBounds(puntosValidos.map(pt =&gt; [pt.lat, pt.lng]))
    map.fitBounds(bounds, { padding: [50, 50], maxZoom: 12 })
  }

  // Limpiar mapa al fin del ciclo de renderizado
  invalidation.then(() =&gt; {
    map.remove()
  })

  return container_mapa
}




































































































